import{_ as e,o as t,c as i,a2 as o}from"./chunks/framework.QoSTM79V.js";const g=JSON.parse('{"title":"Mango Parent","description":"","frontmatter":{},"headers":[],"relativePath":"mango/mango-parent/README.md","filePath":"mango/mango-parent/README.md"}'),s={name:"mango/mango-parent/README.md"};function n(d,a,l,r,h,c){return t(),i("div",null,[...a[0]||(a[0]=[o(`<h1 id="mango-parent" tabindex="-1">Mango Parent <a class="header-anchor" href="#mango-parent" aria-label="Permalink to &quot;Mango Parent&quot;">​</a></h1><h2 id="_1-概览" tabindex="-1">1. 概览 <a class="header-anchor" href="#_1-概览" aria-label="Permalink to &quot;1. 概览&quot;">​</a></h2><p><code>mango-parent</code> 是 Mango 后端 Maven 父 POM，统一 Java 版本、Spring Boot/Spring Cloud BOM、基础依赖版本、构建插件版本和发布仓库配置。</p><p>主要使用者是 Mango 后端模块维护者、业务模块开发者和 CI 构建流程。</p><h2 id="_2-功能清单" tabindex="-1">2. 功能清单 <a class="header-anchor" href="#_2-功能清单" aria-label="Permalink to &quot;2. 功能清单&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>常用入口</th></tr></thead><tbody><tr><td>新增后端模块时继承统一构建基线</td><td>Maven 依赖 / HTTP API / Java API</td></tr><tr><td>升级 Spring Boot、Spring Cloud、MyBatis-Plus、Jackson、JWT、BouncyCastle 等全仓依赖版本</td><td>Maven 依赖 / HTTP API / Java API</td></tr><tr><td>统一 Maven compiler、surefire、checkstyle、spotbugs、pmd 等插件版本</td><td>Maven 依赖 / HTTP API / Java API</td></tr><tr><td>发布 release 或 snapshot 到公司 Maven 仓库</td><td>Maven 依赖 / HTTP API / Java API</td></tr></tbody></table><h2 id="_3-能力边界" tabindex="-1">3. 能力边界 <a class="header-anchor" href="#_3-能力边界" aria-label="Permalink to &quot;3. 能力边界&quot;">​</a></h2><ul><li>不提供运行时代码、Controller、Service、数据库 migration 或业务配置。</li><li>不负责单个模块是否引入某个依赖；这里只做版本和插件管理。</li><li>不替代 <code>mango-admin-starter</code> 的运行时装配。</li></ul><h2 id="_4-模块入口" tabindex="-1">4. 模块入口 <a class="header-anchor" href="#_4-模块入口" aria-label="Permalink to &quot;4. 模块入口&quot;">​</a></h2><p><code>mango-parent/pom.xml</code> 管理：</p><ul><li>Java 17 编译基线。</li><li>Maven 坐标版本变量 <code>revision</code>，默认 <code>1.0.0-SNAPSHOT</code>。</li><li>Spring Boot <code>3.5.14</code>、Spring Cloud <code>2025.0.1</code>。</li><li>Spring Cloud Alibaba Nacos discovery/config starter 版本。</li><li>MyBatis-Plus、springdoc、Knife4j、Swagger annotations、Lombok、JUnit。</li><li>安全敏感依赖版本：JJWT、BouncyCastle、commons-compress、commons-fileupload、plexus-utils。</li><li>Maven compiler、surefire、checkstyle、spotbugs、pmd 等插件版本。</li><li>发布仓库：<code>maven-releases</code>、<code>maven-snapshots</code>。</li></ul><h2 id="_5-接入方式" tabindex="-1">5. 接入方式 <a class="header-anchor" href="#_5-接入方式" aria-label="Permalink to &quot;5. 接入方式&quot;">​</a></h2><p>Mango 后端模块通过父 POM 或 reactor 继承版本管理：</p><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">parent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">groupId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;io.mango&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">groupId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">artifactId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;mango-parent&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">artifactId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">version</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;\${revision}&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">version</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">parent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>业务模块如果在 Mango reactor 内开发，通常不需要重复声明第三方依赖版本；只在 <code>mango-parent</code> 没管理且确实需要固定版本时补充。</p><h2 id="_6-配置说明" tabindex="-1">6. 配置说明 <a class="header-anchor" href="#_6-配置说明" aria-label="Permalink to &quot;6. 配置说明&quot;">​</a></h2><p>无运行时配置。可被构建命令覆盖的 Maven 属性包括：</p><table tabindex="0"><thead><tr><th>属性</th><th>默认值</th><th>含义</th></tr></thead><tbody><tr><td><code>revision</code></td><td><code>1.0.0-SNAPSHOT</code></td><td>当前构建版本。</td></tr><tr><td><code>java.version</code></td><td><code>17</code></td><td>Java 基线。</td></tr><tr><td><code>spring-boot.version</code></td><td><code>3.5.14</code></td><td>Spring Boot BOM。</td></tr><tr><td><code>spring-cloud.version</code></td><td><code>2025.0.1</code></td><td>Spring Cloud BOM。</td></tr><tr><td><code>spring-cloud-alibaba.version</code></td><td><code>2023.0.3.3</code></td><td>Spring Cloud Alibaba Nacos discovery/config starter 版本。</td></tr><tr><td><code>mybatis-plus.version</code></td><td><code>3.5.16</code></td><td>MyBatis-Plus 版本。</td></tr><tr><td><code>junit.version</code></td><td><code>5.10.1</code></td><td>JUnit 版本。</td></tr></tbody></table><p>修改这些属性属于全仓影响，必须扩大验证范围。</p><h2 id="_7-api-与扩展" tabindex="-1">7. API 与扩展 <a class="header-anchor" href="#_7-api-与扩展" aria-label="Permalink to &quot;7. API 与扩展&quot;">​</a></h2><p>无 Java API。对外能力是 Maven <code>dependencyManagement</code>、<code>pluginManagement</code> 和 <code>distributionManagement</code>。</p><h2 id="_8-数据与初始化" tabindex="-1">8. 数据与初始化 <a class="header-anchor" href="#_8-数据与初始化" aria-label="Permalink to &quot;8. 数据与初始化&quot;">​</a></h2><p>无数据库、migration 和初始化数据。</p><h2 id="_9-管理入口" tabindex="-1">9. 管理入口 <a class="header-anchor" href="#_9-管理入口" aria-label="Permalink to &quot;9. 管理入口&quot;">​</a></h2><p>无菜单、权限和租户能力。</p><h2 id="_10-快速开始" tabindex="-1">10. 快速开始 <a class="header-anchor" href="#_10-快速开始" aria-label="Permalink to &quot;10. 快速开始&quot;">​</a></h2><ol><li>新模块继承 <code>mango-parent</code>。</li><li>只声明必要依赖，不重复写 parent 已管理的版本。</li><li>运行模块 <code>mvn test</code>。</li><li>如果新增第三方依赖版本，把版本统一登记到 parent，并说明为什么不是模块私有版本。</li></ol><h2 id="_11-问题排查" tabindex="-1">11. 问题排查 <a class="header-anchor" href="#_11-问题排查" aria-label="Permalink to &quot;11. 问题排查&quot;">​</a></h2><ul><li>依赖版本冲突：先查 <code>mvn dependency:tree</code>，再判断是否应在 parent 统一管理。</li><li>修改 parent 后很多模块失败：这是预期风险，parent 是全仓构建基线。</li><li>发布失败：检查 Maven <code>settings.xml</code> 中 <code>maven-releases</code>、<code>maven-snapshots</code> 凭据。</li></ul><h2 id="_12-相关文档" tabindex="-1">12. 相关文档 <a class="header-anchor" href="#_12-相关文档" aria-label="Permalink to &quot;12. 相关文档&quot;">​</a></h2><ul><li><a href="./../../mango-pmo/rules/backend/05-module">后端模块规范</a></li><li><a href="./../../mango-pmo/rules/08-capability-docs">能力说明维护规范</a></li><li><a href="./../../mango-pmo/rules/05-ai-delivery-quality">AI 交付质量门禁</a></li></ul><h2 id="_13-补充资料" tabindex="-1">13. 补充资料 <a class="header-anchor" href="#_13-补充资料" aria-label="Permalink to &quot;13. 补充资料&quot;">​</a></h2><ul><li><a href="./../../mango-docs/capabilities/README">Mango 能力地图</a></li></ul>`,33)])])}const k=e(s,[["render",n]]);export{g as __pageData,k as default};
